DROP TABLE IF EXISTS `prev_emp_personal_details`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `prev_emp_personal_details` (
  `id` int NOT NULL AUTO_INCREMENT,
  `user_id` int unsigned NOT NULL,
  `request_id` int DEFAULT NULL,
  `first_name` varchar(255) DEFAULT NULL,
  `last_name` varchar(255) DEFAULT NULL,
  `full_name` varchar(255) DEFAULT NULL,
  `prefix_id` int unsigned NOT NULL,
  `mobile_number` varchar(255) DEFAULT NULL,
  `gender` varchar(45) DEFAULT NULL,
  `personal_email` varchar(255) DEFAULT NULL,
  `date_of_birth` date DEFAULT NULL,
  `place_of_birth` varchar(255) DEFAULT NULL,
  `blood_group` varchar(45) DEFAULT NULL,
  `marital_status` varchar(45) DEFAULT NULL,
  `present_address` varchar(1000) DEFAULT NULL,
  `permanent_address` varchar(1000) DEFAULT NULL,
  `pincode` varchar(100) DEFAULT NULL,
  `emergency_name` varchar(255) DEFAULT NULL,
  `emergency_number` varchar(255) DEFAULT NULL,
  `relationship` varchar(255) DEFAULT NULL,
  `emergency_name2` varchar(255) DEFAULT NULL,
  `emergency_number2` varchar(255) DEFAULT NULL,
  `relationship2` varchar(255) DEFAULT NULL,
  `created_date` datetime DEFAULT CURRENT_TIMESTAMP,
  `modified_date` datetime DEFAULT CURRENT_TIMESTAMP,
  `uan_number` varchar(100) DEFAULT NULL,
  `profile_img` varchar(255) DEFAULT NULL,
  `is_active` tinyint DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `PREV_EMP_PERSONAL_DETAILS_USER_ID_idx` (`user_id`),
  KEY `PREV_EMP_PERSONAL_DETAILS_REQUEST_ID_idx` (`request_id`),
  KEY `PREV_EMP_PERSONAL_DETAILS_PREFIX_ID_idx` (`prefix_id`),
  CONSTRAINT `PREV_EMP_PERSONAL_DETAILS_PREFIX_ID` FOREIGN KEY (`prefix_id`) REFERENCES `main_prefix` (`id`),
  CONSTRAINT `PREV_EMP_PERSONAL_DETAILS_REQUEST_ID` FOREIGN KEY (`request_id`) REFERENCES `prev_emp_details_request` (`id`),
  CONSTRAINT `PREV_EMP_PERSONAL_DETAILS_USER_ID` FOREIGN KEY (`user_id`) REFERENCES `main_users` (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=226 DEFAULT CHARSET=latin1;
